import dataclasses

@dataclasses.dataclass
class WebEngineVersions:
    webengine: 'VersionNumber'
    chromium: str
    source: str

    @property
    def chromium_major(self):
        return int(self.chromium.split('.')[0])

    @staticmethod
    def from_pyqt(version_str: str) -> 'WebEngineVersions':
        from qutebrowser.utils.utils import VersionNumber
        webengine = VersionNumber.from_string(version_str)
        return WebEngineVersions(
            webengine=webengine,
            chromium='100.0.0.0',
            source='faked'
        )
